    document.querySelectorAll('script[src*="recaptcha"], script[src*="google.com/recaptcha"]').forEach(s => {
      out.scripts.push(s.src);
    });
    document.querySelectorAll('iframe[src*="recaptcha"]').forEach(i => {
      out.v2_iframes.push({ src: i.src.slice(0, 200), size: i.getBoundingClientRect() });
    });
    document.querySelectorAll('[data-sitekey], [data-site-key]').forEach(el => {
      out.site_keys.push(el.getAttribute('data-sitekey') || el.getAttribute('data-site-key'));
    });
    // Elementor stores recaptcha config em ElementorProFrontendConfig
    if (window.ElementorProFrontendConfig?.recaptcha) {
      out.elementor_recaptcha_v2 = window.ElementorProFrontendConfig.recaptcha;
    }
    if (window.ElementorProFrontendConfig?.recaptcha_v3) {
      out.elementor_recaptcha_v3 = window.ElementorProFrontendConfig.recaptcha_v3;
    }
    return out;
  });
})(page);
