async (page) => {
  // Ignorar erros SSL do cambrasmax.local
  const ctx = page.context();
  await ctx.setExtraHTTPHeaders({});
  await ctx.clearCookies();

  await page.goto('https://cambrasmax.local:8484/?cb=' + Date.now(), { waitUntil: 'networkidle', timeout: 45000 });
  await page.waitForTimeout(1500);
  await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
  await page.waitForTimeout(1500);

  return await page.evaluate(() => {
    const forms = Array.from(document.querySelectorAll('form'));
    const footer = forms.filter(f => !!f.closest('footer, .elementor-location-footer, [data-elementor-type="footer"]'));
    return {
      title: document.title,
      total_forms: forms.length,
      footer_forms: footer.map(f => ({
        name: f.getAttribute('name') || f.id,
        has_email: !!f.querySelector('input[type=email]'),
        has_select: !!f.querySelector('select'),
        submit_label: (f.querySelector('button[type=submit], input[type=submit], .elementor-button[type=submit]')?.innerText || '').trim(),
      })),
    };
  });
}

